sql:
SELECT *
FROM sales_records
WHERE total_price > 50;

SELECT SUM(total_price) 
FROM sales_records 
WHERE brand_id = 1 AND strftime('%m', transaction_date) = '03';

external_knowledge:
'Item A' refers to a specific product in the sales records;
Ebb and flow metaphorically describe the decrease and increase in sales;
Ripple represents each monthly period of sales.

sql:
SELECT *
FROM sales_analysis
ORDER BY total_sales DESC;

SELECT AVG(total_sales) 
FROM sales_analysis 
WHERE brand_id = 1 AND year = 2019;

SELECT *
FROM low_inventory_alerts
WHERE item_id = 0 AND threshold = 20;
